import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_shouldReturnFactoryThatCreatesAdapterForMatchingType() {
    // Arrange
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);
    @SuppressWarnings("unchecked")
    TypeAdapter<String> stringAdapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactory(stringTypeToken, stringAdapter);

    Gson gson = mock(Gson.class);

    // Act & Assert
    // When typeToken equals the factory's type, it should return the adapter
    TypeAdapter<String> adapter = factory.create(gson, stringTypeToken);
    assertSame(stringAdapter, adapter);

    // When typeToken does not equal, it should return null
    TypeToken<Integer> intTypeToken = TypeToken.get(Integer.class);
    TypeAdapter<?> nullAdapter = factory.create(gson, intTypeToken);
    assertNull(nullAdapter);
  }
}
